inline bool VerifyFieldValueVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<FieldValue> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyFieldValue(
        verifier,  values->Get(i), types->GetEnum<FieldValue>(i))) {
      return false;
    }
  }
  return true;
}

